// Custom alchemy Resource for AWS Key Pair.
// Generated by stackpanel — static library code.
import type { Context } from "alchemy";
import { Resource } from "alchemy";

export interface KeyPairProps {
  keyName: string;
  publicKey: string;
  tags?: Record<string, string>;
  destroyOnDelete?: boolean;
}

export interface KeyPair {
  keyName: string;
  keyPairId?: string;
  adopted?: boolean;
}

function hasTags(tags: Record<string, string> | undefined): tags is Record<string, string> {
  return Boolean(tags && Object.keys(tags).length > 0);
}

export const KeyPair = Resource(
  "stackpanel::KeyPair",
  async function (
    this: Context<KeyPair>,
    _id: string,
    props: KeyPairProps,
  ): Promise<KeyPair> {
    const {
      EC2Client,
      DescribeKeyPairsCommand,
      ImportKeyPairCommand,
      CreateTagsCommand,
      DeleteKeyPairCommand,
    } = await import("@aws-sdk/client-ec2");

    const client = new EC2Client({});

    if (this.phase === "delete") {
      if (props.destroyOnDelete === false) {
        return this.destroy();
      }

      try {
        await client.send(new DeleteKeyPairCommand({ KeyName: props.keyName }));
      } catch (err: any) {
        if (err.name !== "InvalidKeyPair.NotFound") throw err;
      }

      return this.destroy();
    }

    let adopted = this.output?.adopted ?? false;
    let keyPairId = this.output?.keyPairId;

    try {
      const existing = await client.send(
        new DescribeKeyPairsCommand({ KeyNames: [props.keyName] }),
      );
      const found = existing.KeyPairs?.[0];
      if (found?.KeyPairId) {
        adopted = true;
        keyPairId = found.KeyPairId;
      }
    } catch (err: any) {
      if (err.name !== "InvalidKeyPair.NotFound") throw err;
    }

    if (!keyPairId) {
      const imported = await client.send(
        new ImportKeyPairCommand({
          KeyName: props.keyName,
          PublicKeyMaterial: Buffer.from(props.publicKey),
          TagSpecifications: hasTags(props.tags)
            ? [
                {
                  ResourceType: "key-pair",
                  Tags: Object.entries(props.tags).map(([Key, Value]) => ({
                    Key,
                    Value,
                  })),
                },
              ]
            : undefined,
        }),
      );
      keyPairId = imported.KeyPairId;
    } else if (hasTags(props.tags)) {
      await client.send(
        new CreateTagsCommand({
          Resources: [keyPairId],
          Tags: Object.entries(props.tags).map(([Key, Value]) => ({ Key, Value })),
        }),
      );
    }

    return {
      keyName: props.keyName,
      keyPairId,
      adopted,
    };
  },
);
